import { describe, test, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, writeFileSync, rmSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import {
  extractEditedFiles,
  extractScopeFragments,
  isInScope,
  subagentScopeAuditor,
} from '../../subagent-stop/subagent-scope-auditor.js';
import { NOOP_CTX } from '../../lib/context.js';

describe('subagent-scope-auditor — pure logic', () => {
  let tmp: string;

  beforeEach(() => {
    tmp = mkdtempSync(join(tmpdir(), 'scope-test-'));
  });
  afterEach(() => {
    rmSync(tmp, { recursive: true, force: true });
  });

  describe('extractEditedFiles', () => {
    test('returns [] when transcript does not exist', () => {
      expect(extractEditedFiles(join(tmp, 'missing.jsonl'))).toEqual([]);
    });

    test('extracts Write/Edit/MultiEdit targets, dedupes, preserves order', () => {
      const p = join(tmp, 't.jsonl');
      const lines = [
        JSON.stringify({ type: 'assistant', tool_use: { name: 'Write', input: { file_path: '/a.ts' } } }),
        JSON.stringify({ type: 'assistant', tool_use: { name: 'Read', input: { file_path: '/b.ts' } } }),
        JSON.stringify({ type: 'assistant', tool_use: { name: 'Edit', input: { file_path: '/c.ts' } } }),
        JSON.stringify({ type: 'assistant', tool_use: { name: 'Write', input: { file_path: '/a.ts' } } }),
      ].join('\n');
      writeFileSync(p, lines, 'utf8');
      expect(extractEditedFiles(p)).toEqual(['/a.ts', '/c.ts']);
    });
  });

  describe('extractScopeFragments', () => {
    test('pulls paths with extensions', () => {
      const frags = extractScopeFragments('Fix src/auth/login.py — the reset flow');
      expect(frags.has('src/auth/login.py')).toBe(true);
    });

    test('pulls meaningful bare words, filters stopwords', () => {
      const frags = extractScopeFragments('fix the auth reset flow');
      expect(frags.has('auth')).toBe(true);
      expect(frags.has('reset')).toBe(true);
      expect(frags.has('flow')).toBe(true);
      expect(frags.has('fix')).toBe(false); // common word — excluded
      expect(frags.has('the')).toBe(false);
    });

    test('empty for empty prompt', () => {
      expect(extractScopeFragments('').size).toBe(0);
    });
  });

  describe('isInScope', () => {
    test('empty scope returns true (can\'t audit)', () => {
      expect(isInScope('/any.ts', new Set())).toBe(true);
    });

    test('matches by full path', () => {
      expect(isInScope('/src/auth.py', new Set(['/src/auth.py']))).toBe(true);
    });

    test('matches by basename', () => {
      expect(isInScope('/some/dir/auth.py', new Set(['auth.py']))).toBe(true);
    });

    test('matches by substring fragment', () => {
      expect(isInScope('/src/auth/login.py', new Set(['auth']))).toBe(true);
    });

    test('rejects unrelated file', () => {
      expect(isInScope('/src/billing/rates.ts', new Set(['auth', 'login']))).toBe(false);
    });
  });

  describe('subagentScopeAuditor — end-to-end', () => {
    test('silent without transcript path', () => {
      const r = subagentScopeAuditor({} as never, { ...NOOP_CTX, projectDir: tmp });
      expect(r.hookSpecificOutput).toBeUndefined();
    });

    test('flags out-of-scope edits', () => {
      const p = join(tmp, 't.jsonl');
      const lines = [
        JSON.stringify({ type: 'user', message: { content: 'Fix src/auth/login.py — password reset' } }),
        JSON.stringify({ type: 'assistant', tool_use: { name: 'Write', input: { file_path: '/src/auth/login.py' } } }),
        JSON.stringify({ type: 'assistant', tool_use: { name: 'Write', input: { file_path: '/src/billing/rates.ts' } } }),
      ].join('\n');
      writeFileSync(p, lines, 'utf8');

      const input = { agent_transcript_path: p } as never;
      const r = subagentScopeAuditor(input, { ...NOOP_CTX, projectDir: tmp });
      const ctx = (r.hookSpecificOutput as { additionalContext?: string })?.additionalContext;
      expect(ctx).toBeDefined();
      expect(ctx).toContain('[subagent-scope-auditor]');
      expect(ctx).toContain('billing/rates.ts');
      expect(ctx).not.toContain('login.py'); // in-scope
    });
  });
});
